set -eu; f=queue-admission.json; if [ ! -s "$f" ]; then echo 'FAIL: queue-admission.json missing or empty' >&2; exit 1; fi; python3 - <<'PY'
import json
from pathlib import Path
p=Path('queue-admission.json')
try: d=json.loads(p.read_text())
except Exception as e: raise SystemExit(f'FAIL: invalid JSON: {e}')
req={'generated_at_utc','source','bead_id','constraints','eligible_candidates','exclusions','eligible_count','verdict','next_action'}
missing=sorted(req-set(d))
if missing: raise SystemExit(f'FAIL: missing keys: {missing}')
if d['bead_id']!='hermes-jxk0': raise SystemExit('FAIL: wrong bead_id')
if not isinstance(d['constraints'],list) or not d['constraints']: raise SystemExit('FAIL: constraints must be non-empty')
if not isinstance(d['eligible_candidates'],list): raise SystemExit('FAIL: eligible_candidates must be an array')
if d['eligible_count']!=len(d['eligible_candidates']): raise SystemExit('FAIL: eligible_count mismatch')
if d['verdict'] not in {'ADMIT','HOLD'}: raise SystemExit('FAIL: verdict must be ADMIT or HOLD')
if d['verdict']=='ADMIT' and d['eligible_count']<10: raise SystemExit('FAIL: ADMIT requires at least 10 candidates')
ids=[]
for i,c in enumerate(d['eligible_candidates']):
    need={'id','identifier','title','status','assigneeAgentId','rationale'}
    if not need.issubset(c): raise SystemExit(f'FAIL: candidate {i} missing fields')
    ids.append(c['id'])
if len(ids)!=len(set(ids)): raise SystemExit('FAIL: duplicate candidate IDs')
if not isinstance(d['exclusions'],list) or not d['exclusions']: raise SystemExit('FAIL: exclusions must be non-empty')
for i,x in enumerate(d['exclusions']):
    if not {'identifier','reason'}.issubset(x): raise SystemExit(f'FAIL: exclusion {i} missing fields')
if not isinstance(d['next_action'],str) or len(d['next_action'].strip())<20: raise SystemExit('FAIL: next_action is not concrete')
print(f"EXECUTED_CHECK=PASS queue-admission verdict={d['verdict']} eligible_count={d['eligible_count']}")
PY
